class WalletStore(
    private val context: Context
) {
    private val prefs: SharedPreferences = SecurePrefs.create(context, "wallet_store")

    private val scope = CoroutineScope(SupervisorJob() + Dispatchers.Main.immediate)

    fun close() {
        scope.cancel()
    }

    @WorkerThread
    fun getBalanceCents(currency: String): Long {
        val key = "balance_${currency.uppercase()}"
        return prefs.getLong(key, 0L)
    }

    @WorkerThread
    fun getAllBalances(): Map<String, Long> {
        val out = linkedMapOf<String, Long>()
        for ((k, v) in prefs.all) {
            if (k.startsWith("balance_") && v is Long) {
                out[k.removePrefix("balance_")] = v
            }
        }
        return out
    }

    @WorkerThread
    fun listTransactions(limit: Int = 50): List<WalletTransaction> {
        val raw = prefs.getString("tx_list", "[]") ?: "[]"
        val arr = JSONArray(raw)
        val out = ArrayList<WalletTransaction>(arr.length())
        val start = maxOf(0, arr.length() - limit)
        for (i in start until arr.length()) {
            val o = arr.getJSONObject(i)
            out.add(
                WalletTransaction(
                    id = o.getString("id"),
                    type = WalletTransaction.Type.valueOf(o.getString("type")),
                    amountCents = o.getLong("amountCents"),
                    currency = o.getString("currency"),
                    createdAtMs = o.getLong("createdAtMs"),
                    note = o.optString("note", null),
                    externalRef = o.optString("externalRef", null)
                )
            )
        }
        return out.reversed()
    }

    @WorkerThread
    fun applyTransaction(tx: WalletTransaction): PaymentResult {
        if (tx.amountCents <= 0) return PaymentResult.Failure("invalid_amount", "Amount must be > 0", recoverable = false)
        if (tx.currency.isBlank()) return PaymentResult.Failure("invalid_currency", "Currency required", recoverable = false)

        synchronized(this) {
            val currency = tx.currency.uppercase()
            val balanceKey = "balance_$currency"
            val current = prefs.getLong(balanceKey, 0L)

            val newBalance = when (tx.type) {
                WalletTransaction.Type.CREDIT -> safeAdd(current, tx.amountCents)
                WalletTransaction.Type.DEBIT -> safeSub(current, tx.amountCents)
            } ?: return PaymentResult.Failure("overflow", "Balance overflow", recoverable = false)

            if (tx.type == WalletTransaction.Type.DEBIT && newBalance < 0L) {
                return PaymentResult.Failure("insufficient_funds", "Insufficient funds", recoverable = true)
            }

            val txListRaw = prefs.getString("tx_list", "[]") ?: "[]"
            val arr = JSONArray(txListRaw)

            val o = JSONObject()
            o.put("id", tx.id)
            o.put("type", tx.type.name)
            o.put("amountCents", tx.amountCents)
            o.put("currency", currency)
            o.put("createdAtMs", tx.createdAtMs)
            if (tx.note != null) o.put("note", tx.note)
            if (tx.externalRef != null) o.put("externalRef", tx.externalRef)

            arr.put(o)

            prefs.edit()
                .putLong(balanceKey, newBalance)
                .putString("tx_list", arr.toString())
                .apply()

            return PaymentResult.Success(transactionId = tx.id, metadata = mapOf("currency" to currency, "newBalanceCents" to newBalance.toString()))
        }
    }

    private fun safeAdd(a: Long, b: Long): Long? {
        val r = a + b
        if (((a xor r) and (b xor r)) < 0) return null
        return r
    }

    private fun safeSub(a: Long, b: Long): Long? {
        val r = a - b
        if (((a xor b) and (a xor r)) < 0) return null
        return r
    }
