    private fun persistPurchaseToken(purchase: Purchase) {
        val token = purchase.purchaseToken ?: return
        val hash = sha256Base16(token)
        prefs.edit().putBoolean("pt_$hash", true).apply()
    }

    private fun isRecoverable(code: Int): Boolean {
        return when (code) {
            BillingClient.BillingResponseCode.SERVICE_DISCONNECTED,
            BillingClient.BillingResponseCode.SERVICE_UNAVAILABLE,
            BillingClient.BillingResponseCode.BILLING_UNAVAILABLE,
            BillingClient.BillingResponseCode.NETWORK_ERROR,
            BillingClient.BillingResponseCode.ERROR,
            BillingClient.BillingResponseCode.ITEM_UNAVAILABLE -> true
            else -> false
        }
    }

    private fun mapBillingCode(code: Int): String {
        return when (code) {
            BillingClient.BillingResponseCode.OK -> "ok"
            BillingClient.BillingResponseCode.USER_CANCELED -> "user_canceled"
            BillingClient.BillingResponseCode.SERVICE_DISCONNECTED -> "service_disconnected"
            BillingClient.BillingResponseCode.SERVICE_UNAVAILABLE -> "service_unavailable"
            BillingClient.BillingResponseCode.BILLING_UNAVAILABLE -> "billing_unavailable"
            BillingClient.BillingResponseCode.ITEM_UNAVAILABLE -> "item_unavailable"
            BillingClient.BillingResponseCode.DEVELOPER_ERROR -> "developer_error"
            BillingClient.BillingResponseCode.ERROR -> "error"
            BillingClient.BillingResponseCode.ITEM_ALREADY_OWNED -> "item_already_owned"
            BillingClient.BillingResponseCode.ITEM_NOT_OWNED -> "item_not_owned"
            BillingClient.BillingResponseCode.NETWORK_ERROR -> "network_error"
            BillingClient.BillingResponseCode.FEATURE_NOT_SUPPORTED -> "feature_not_supported"
            else -> "unknown_$code"
        }
    }

    private fun sha256Base16(input: String): String {
        val md = MessageDigest.getInstance("SHA-256")
        val bytes = md.digest(input.toByteArray(Charsets.UTF_8))
        val sb = StringBuilder(bytes.size * 2)
        for (b in bytes) sb.append(((b.toInt() and 0xFF) + 0x100).toString(16).substring(1))
        return sb.toString()
    }
}

object SecurePrefs {

    fun create(context: Context, name: String): SharedPreferences {
        return try {
            val masterKey = MasterKey.Builder(context)
                .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
                .build()

            EncryptedSharedPreferences.create(
                context,
                name,
                masterKey,
                EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
                EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
            )
        } catch (_: Throwable) {
            context.getSharedPreferences(name, Context.MODE_PRIVATE)
        }
    }
}

object DeviceCompatibility {

    fun isPlayBillingSupported(): Boolean = true

    fun supportsStrongBox(): Boolean {
        if (Build.VERSION.SDK_INT < Build.VERSION_CODES.P) return false
        return try {
            val ks = java.security.KeyStore.getInstance("AndroidKeyStore")
            ks.load(null)
            true
        } catch (_: Throwable) {
            false
        }
    }

    fun apiLevel(): Int = Build.VERSION.SDK_INT
}

class PaymentFacade(
    private val module: PaymentModule
) {
    fun initBilling() = module.billingManager().init()

    fun queryIapProducts(
        productIds: List<String>,
        onResult: (PaymentResult, List<ProductDetails>) -> Unit
    ) {
        module.billingManager().queryProductDetails(
            products = productIds.map { InAppBillingManager.ProductQuery(it, BillingClient.ProductType.INAPP) },
            onResult = onResult
        )
    }

    fun querySubsProducts(
        productIds: List<String>,
        onResult: (PaymentResult, List<ProductDetails>) -> Unit
    ) {
        module.billingManager().queryProductDetails(
            products = productIds.map { InAppBillingManager.ProductQuery(it, BillingClient.ProductType.SUBS) },
            onResult = onResult
        )
    }

    fun buy(
        activity: Activity,
        productDetails: ProductDetails,
        offerToken: String? = null,
        obfuscatedAccountId: String? = null,
        obfuscatedProfileId: String? = null
    ): PaymentResult {
        return module.billingManager().launchPurchaseFlow(
            activity = activity,
            productDetails = productDetails,
            offerToken = offerToken,
            obfuscatedAccountId = obfuscatedAccountId,
            obfuscatedProfileId = obfuscatedProfileId
        )
    }

    fun restore(onResult: (PaymentResult, List<Purchase>) -> Unit) {
        module.billingManager().restorePurchases(onResult)
    }

    fun acknowledgeIfNeeded(purchase: Purchase, onResult: (PaymentResult) -> Unit) {
        module.billingManager().acknowledgeIfNeeded(purchase, onResult)
    }

    fun consume(purchaseToken: String, onResult: (PaymentResult) -> Unit) {
        module.billingManager().consumePurchase(purchaseToken, onResult)
    }

    suspend fun walletBalance(currency: String): Long = withContext(Dispatchers.IO) {
        module.wallet().getBalanceCents(currency)
    }

    suspend fun walletTransactions(limit: Int = 50): List<WalletTransaction> = withContext(Dispatchers.IO) {
        module.wallet().listTransactions(limit)
    }

    suspend fun walletCredit(amountCents: Long, currency: String, note: String? = null, externalRef: String? = null): PaymentResult =
        withContext(Dispatchers.IO) {
            module.wallet().applyTransaction(
                WalletTransaction(
                    type = WalletTransaction.Type.CREDIT,
                    amountCents = amountCents,
                    currency = currency,
                    note = note,
                    externalRef = externalRef
                )
            )
        }

    suspend fun walletDebit(amountCents: Long, currency: String, note: String? = null, externalRef: String? = null): PaymentResult =
        withContext(Dispatchers.IO) {
            module.wallet().applyTransaction(
                WalletTransaction(
                    type = WalletTransaction.Type.DEBIT,
                    amountCents = amountCents,
                    currency = currency,
                    note = note,
                    externalRef = externalRef
                )
            )
        }
}